1	/**
2	 * SIGNAL News Trading Terminal — Frontend Application
3	 * Auto-refreshing financial news aggregator with sentiment analysis
4	 */
5	
6	"use strict";
7	
8	import SignalAuth from './auth.js';
9	
10	// ---------------------------------------------------------------------------
11	// Config
12	// ---------------------------------------------------------------------------
13	
14	const API = "/api";
15	const DEFAULT_LIMIT = 200;
16	const NEW_THRESHOLD_MS = 60000; // 60 seconds
17	
18	// ---------------------------------------------------------------------------
19	// State
20	// ---------------------------------------------------------------------------
21	
22	let state = {
23	  items: [],
24	  seenIds: new Set(),
25	  newIds: new Set(),
26	  sources: [],
27	  stats: null,
28	  filter: {
29	    sentiment: "all",
30	    sources: new Set(), // empty = all selected
31	    query: "",
32	    dateFrom: "",
33	    dateTo: "",
34	    hideDuplicates: false,
35	  },
36	  refreshInterval: 5000,
37	  refreshTimer: null,
38	  lastRefresh: null,
39	  connected: false,
40	  loading: true,
41	  totalFetched: 0,
42	  fetchCount: 0,
43	  itemsPerSecond: 0,
44	  startTime: Date.now(),
45	  sidebarOpen: false,
46	  modalOpen: false,
47	  detailModalOpen: false,
48	  detailItem: null,
49	  userTier: null,
50	  userFeatures: {},
51	  soundEnabled: false,
52	};
53	
54	// ---------------------------------------------------------------------------
55	// DOM References
56	// ---------------------------------------------------------------------------
57	
58	const $ = (sel) => document.querySelector(sel);
59	const $$ = (sel) => [...document.querySelectorAll(sel)];
60	
61	// ---------------------------------------------------------------------------
62	// Utilities
63	// ---------------------------------------------------------------------------
64	
65	function formatTime(dateStr) {
66	  if (!dateStr) return "--:--:--";
67	  try {
68	    const d = new Date(dateStr);
69	    if (isNaN(d.getTime())) return "--:--:--";
70	    return d.toLocaleTimeString("en-US", { hour12: false, hour: "2-digit", minute: "2-digit", second: "2-digit" });
71	  } catch {
72	    return "--:--:--";
73	  }
74	}
75	
76	function formatDate(dateStr) {
77	  if (!dateStr) return "";
78	  try {
79	    const d = new Date(dateStr);
80	    if (isNaN(d.getTime())) return "";
81	    return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
82	  } catch {
83	    return "";
84	  }
85	}
86	
87	function timeAgo(dateStr) {
88	  if (!dateStr) return "";
89	  try {
90	    const d = new Date(dateStr);
91	    const now = new Date();
92	    const diff = now - d;
93	    if (diff < 0) return "just now";
94	    if (diff < 60000) return `${Math.floor(diff / 1000)}s ago`;
95	    if (diff < 3600000) return `${Math.floor(diff / 60000)}m ago`;
96	    if (diff < 86400000) return `${Math.floor(diff / 3600000)}h ago`;
97	    return `${Math.floor(diff / 86400000)}d ago`;
98	  } catch {
99	    return "";
100	  }
101	}
102	
103	function isNew(dateStr) {
104	  if (!dateStr) return false;
105	  try {
106	    const d = new Date(dateStr);
107	    return (Date.now() - d.getTime()) < NEW_THRESHOLD_MS;
108	  } catch {
109	    return false;
110	  }
111	}
112	
113	function escapeHtml(str) {
114	  const div = document.createElement("div");
115	  div.textContent = str;
116	  return div.innerHTML;
117	}
118	
119	function truncate(str, max) {
120	  if (!str) return "";
121	  return str.length > max ? str.slice(0, max) + "\u2026" : str;
122	}
123	
124	// ---------------------------------------------------------------------------
125	// API Calls
126	// ---------------------------------------------------------------------------
127	
128	async function fetchNews() {
129	  try {
130	    const params = new URLSearchParams({ limit: DEFAULT_LIMIT });
131	    if (state.filter.dateFrom) params.set("from", state.filter.dateFrom);
132	    if (state.filter.dateTo) params.set("to", state.filter.dateTo);
133	    const res = await SignalAuth.fetch(`${API}/news?${params}`);
134	    if (!res.ok) throw new Error(`HTTP ${res.status}`);
135	    const data = await res.json();
136	    state.connected = true;
137	    state.loading = false;
138	    state.fetchCount++;
139	    state.lastRefresh = new Date().toISOString();
140	
141	    if (data.items && data.items.length > 0) {
142	      // Detect new items
143	      const newIds = new Set();
144	      for (const item of data.items) {
145	        if (!state.seenIds.has(item.id)) {
146	          newIds.add(item.id);
147	          state.seenIds.add(item.id);
148	        }
149	      }
150	
151	      // Play sound for new items if enabled
152	      if (state.soundEnabled && newIds.size > 0 && state.fetchCount > 1) {
153	        playNotificationSound();
154	      }
155	
156	      state.newIds = newIds;
157	      state.items = data.items;
158	      state.totalFetched = data.count;
159	
160	      // Calculate items/second
161	      const elapsed = (Date.now() - state.startTime) / 1000;
162	      state.itemsPerSecond = elapsed > 0 ? (state.totalFetched / elapsed).toFixed(1) : 0;
163	    }
164	
165	    renderNews();
166	    updateStatusBar();
167	    updateConnectionStatus(true);
168	  } catch (err) {
169	    state.connected = false;
170	    state.loading = false;
171	    updateConnectionStatus(false);
172	    if (state.items.length === 0) {
173	      renderEmpty("Unable to connect to API. Retrying...");
174	    }
175	  }
176	}
177	
178	async function fetchSources() {
179	  try {
180	    const res = await SignalAuth.fetch(`${API}/sources`);
181	    if (!res.ok) return;
182	    const data = await res.json();
183	    state.sources = data.sources || [];
184	    renderSources();
185	  } catch {
186	    // silent
187	  }
188	}
189	
190	async function fetchStats() {
191	  try {
192	    const res = await SignalAuth.fetch(`${API}/stats`);
193	    if (!res.ok) return;
194	    state.stats = await res.json();
195	    updateHeaderStats();
196	  } catch {
197	    // silent
198	  }
199	}
200	
201	async function forceRefresh() {
202	  try {
203	    const btn = $("#btn-refresh");
204	    if (btn) {
205	      btn.disabled = true;
206	      btn.innerHTML = `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" class="spinning"><path d="M21 12a9 9 0 11-6.219-8.56"/></svg>Refreshing`;
207	    }
208	    await SignalAuth.fetch(`${API}/refresh`, { method: "POST" });
209	    await fetchNews();
210	    await fetchStats();
211	    if (btn) {
212	      btn.disabled = false;
213	      btn.innerHTML = `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 12a9 9 0 11-6.219-8.56"/><path d="M22 3v6h-6"/></svg>Refresh`;
214	    }
215	  } catch {
216	    const btn = $("#btn-refresh");
217	    if (btn) {
218	      btn.disabled = false;
219	      btn.innerHTML = `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 12a9 9 0 11-6.219-8.56"/><path d="M22 3v6h-6"/></svg>Refresh`;
220	    }
221	  }
222	}
223	
224	// ---------------------------------------------------------------------------
225	// Sound
226	// ---------------------------------------------------------------------------
227	
228	function playNotificationSound() {
229	  try {
230	    const ctx = new (window.AudioContext || window.webkitAudioContext)();
231	    const osc = ctx.createOscillator();
232	    const gain = ctx.createGain();
233	    osc.connect(gain);
234	    gain.connect(ctx.destination);
235	    osc.type = "sine";
236	    osc.frequency.setValueAtTime(880, ctx.currentTime);
237	    osc.frequency.setValueAtTime(1100, ctx.currentTime + 0.05);
238	    gain.gain.setValueAtTime(0.08, ctx.currentTime);
239	    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.15);
240	    osc.start(ctx.currentTime);
241	    osc.stop(ctx.currentTime + 0.15);
242	  } catch {
243	    // silent
244	  }
245	}
246	
247	// ---------------------------------------------------------------------------
248	// Filtering
249	// ---------------------------------------------------------------------------
250	
251	function getFilteredItems() {
252	  return state.items.filter((item) => {
253	    // Sentiment filter
254	    if (state.filter.sentiment !== "all" && item.sentiment_label !== state.filter.sentiment) {
255	      return false;
256	    }
257	    // Source filter
258	    if (state.filter.sources.size > 0 && !state.filter.sources.has(item.source)) {
259	      return false;
260	    }
261	    // Query filter
262	    if (state.filter.query) {
263	      const q = state.filter.query.toLowerCase();
264	      const inTitle = (item.title || "").toLowerCase().includes(q);
265	      const inSummary = (item.summary || "").toLowerCase().includes(q);
266	      if (!inTitle && !inSummary) return false;
267	    }
268	    // Duplicate filter
269	    if (state.filter.hideDuplicates && item.duplicate) {
270	      return false;
271	    }
272	    return true;
273	  });
274	}
275	
276	function getSentimentCounts() {
277	  const counts = { all: 0, bullish: 0, bearish: 0, neutral: 0 };
278	  for (const item of state.items) {
279	    counts.all++;
280	    if (counts[item.sentiment_label] !== undefined) {
281	      counts[item.sentiment_label]++;
282	    }
283	  }
284	  return counts;
285	}
286	
287	// ---------------------------------------------------------------------------
288	// Rendering
289	// ---------------------------------------------------------------------------
290	
291	function renderNews() {
292	  const container = $("#news-body");
293	  if (!container) return;
294	
295	  const items = getFilteredItems();
296	
297	  if (items.length === 0 && !state.loading) {
298	    container.innerHTML = `
299	      <tr>
300	        <td colspan="5">
301	          <div class="empty-state">
302	            <div class="icon">\u25C7</div>
303	            <div>No items match current filters</div>
304	            <div style="font-size:11px">Try adjusting sentiment or source filters</div>
305	          </div>
306	        </td>
307	      </tr>`;
308	    return;
309	  }
310	
311	  const rows = items.map((item) => {
312	    const isNewItem = state.newIds.has(item.id);
313	    const isFresh = isNew(item.fetched_at);
314	    const rowClass = isNewItem ? "news-row-new" : "";
315	    const pubTime = formatTime(item.published);
316	    const ago = timeAgo(item.published);
317	    const dupBadge = item.duplicate ? '<span class="badge-dup">DUP</span>' : '';
318	
319	    return `<tr class="${rowClass}" data-id="${item.id}">
320	      <td class="cell-time" title="${ago}">${pubTime}</td>
321	      <td><span class="sentiment-badge ${item.sentiment_label}"><span class="sentiment-dot"></span>${item.sentiment_label}</span></td>
322	      <td><span class="source-tag">${escapeHtml(item.source || "")}</span></td>
323	      <td class="cell-headline">
324	        <a href="${escapeHtml(item.link || "#")}" target="_blank" rel="noopener noreferrer">${escapeHtml(item.title || "Untitled")}</a>${isFresh ? '<span class="badge-new">NEW</span>' : ''}${dupBadge}
325	      </td>
326	      <td class="cell-summary">${escapeHtml(truncate(item.summary, 120))}</td>
327	    </tr>`;
328	  });
329	
330	  container.innerHTML = rows.join("");
331	  updateSentimentFilters();
332	  updateItemCount();
333	}
334	
335	function renderSkeleton() {
336	  const container = $("#news-body");
337	  if (!container) return;
338	  const rows = Array.from({ length: 15 }, (_, i) => {
339	    const w1 = 50 + Math.random() * 20;
340	    const w2 = 200 + Math.random() * 200;
341	    const w3 = 100 + Math.random() * 100;
342	    return `<tr class="skeleton-row">
343	      <td><div class="skeleton-block" style="width:${w1}px"></div></td>
344	      <td><div class="skeleton-block" style="width:60px"></div></td>
345	      <td><div class="skeleton-block" style="width:80px"></div></td>
346	      <td><div class="skeleton-block" style="width:${w2}px"></div></td>
347	      <td><div class="skeleton-block" style="width:${w3}px"></div></td>
348	    </tr>`;
349	  });
350	  container.innerHTML = rows.join("");
351	}
352	
353	function renderEmpty(message) {
354	  const container = $("#news-body");
355	  if (!container) return;
356	  container.innerHTML = `
357	    <tr>
358	      <td colspan="5">
359	        <div class="loading-state">
360	          <div class="loading-spinner"></div>
361	          <div>${escapeHtml(message)}</div>
362	        </div>
363	      </td>
364	    </tr>`;
365	}
366	
367	function renderSources() {
368	  const container = $("#source-list");
369	  if (!container) return;
370	
371	  if (!state.sources.length) {
372	    // Show all feed names from a static list
373	    const feedNames = [
374	      "CNBC", "CNBC_World", "Reuters_Business", "MarketWatch", "MarketWatch_Markets",
375	      "Investing_com", "Yahoo_Finance", "Nasdaq", "SeekingAlpha", "Benzinga",
376	      "AP_News", "Bloomberg_Business", "Bloomberg_Markets",
377	      "BBC_Business", "Google_News_Business"
378	    ];
379	    container.innerHTML = feedNames.map((name) => `
380	      <label class="source-item">
381	        <input type="checkbox" checked data-source="${name}">
382	        <span>${name.replace(/_/g, " ")}</span>
383	        <span class="source-count">--</span>
384	      </label>`).join("");
385	  } else {
386	    container.innerHTML = state.sources.map((s) => `
387	      <label class="source-item">
388	        <input type="checkbox" checked data-source="${s.name}">
389	        <span>${s.name.replace(/_/g, " ")}</span>
390	        <span class="source-count">${s.total_items}</span>
391	      </label>`).join("");
392	  }
393	
394	  // Bind change events
395	  container.querySelectorAll('input[type="checkbox"]').forEach((cb) => {
396	    cb.addEventListener("change", () => {
397	      updateSourceFilter();
398	      renderNews();
399	    });
400	  });
401	}
402	
403	function updateSourceFilter() {
404	  const unchecked = new Set();
405	  const allChecked = [];
406	  $$('#source-list input[type="checkbox"]').forEach((cb) => {
407	    if (!cb.checked) {
408	      unchecked.add(cb.dataset.source);
409	    } else {
410	      allChecked.push(cb.dataset.source);
411	    }
412	  });
413	  // If all are checked, sources is empty (meaning "all")
414	  if (unchecked.size === 0) {
415	    state.filter.sources = new Set();
416	  } else {
417	    state.filter.sources = new Set(allChecked);
418	  }
419	}
420	
421	function updateSentimentFilters() {
422	  const counts = getSentimentCounts();
423	  const countEls = {
424	    all: $("#sentiment-count-all"),
425	    bullish: $("#sentiment-count-bullish"),
426	    bearish: $("#sentiment-count-bearish"),
427	    neutral: $("#sentiment-count-neutral"),
428	  };
429	  Object.entries(countEls).forEach(([key, el]) => {
430	    if (el) el.textContent = counts[key] || 0;
431	  });
432	}
433	
434	function updateItemCount() {
435	  const el = $("#total-items");
436	  if (el) {
437	    const filtered = getFilteredItems();
438	    el.textContent = filtered.length;
439	  }
440	}
441	
442	function updateHeaderStats() {
443	  if (!state.stats) return;
444	  const el = $("#total-items");
445	  if (el && state.filter.sentiment === "all" && state.filter.sources.size === 0 && !state.filter.query) {
446	    el.textContent = state.stats.total_items;
447	  }
448	  const feedCountEl = $("#feed-count");
449	  if (feedCountEl) feedCountEl.textContent = state.stats.feed_count;
450	  const avgSentEl = $("#avg-sentiment");
451	  if (avgSentEl) {
452	    const score = state.stats.avg_sentiment_score;
453	    avgSentEl.textContent = (score >= 0 ? "+" : "") + score.toFixed(3);
454	    avgSentEl.style.color = score > 0.05 ? "var(--green)" : score < -0.05 ? "var(--red)" : "var(--yellow)";
455	  }
456	}
457	
458	function updateConnectionStatus(connected) {
459	  const dot = $("#connection-dot");
460	  const label = $("#connection-label");
461	  if (dot) {
462	    dot.className = connected ? "status-dot connected" : "status-dot disconnected";
463	  }
464	  if (label) {
465	    label.textContent = connected ? "LIVE" : "DISCONNECTED";
466	  }
467	}
468	
469	function updateStatusBar() {
470	  const lastRefreshEl = $("#last-refresh");
471	  if (lastRefreshEl && state.lastRefresh) {
472	    lastRefreshEl.textContent = formatTime(state.lastRefresh);
473	  }
474	  const ipsEl = $("#items-per-sec");
475	  if (ipsEl) {
476	    ipsEl.textContent = state.itemsPerSecond;
477	  }
478	}
479	
480	// ---------------------------------------------------------------------------
481	// Clock
482	// ---------------------------------------------------------------------------
483	
484	function updateClock() {
485	  const el = $("#clock");
486	  if (!el) return;
487	  const now = new Date();
488	  const time = now.toLocaleTimeString("en-US", { hour12: false, hour: "2-digit", minute: "2-digit", second: "2-digit" });
489	  const date = now.toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric", year: "numeric" });
490	  el.textContent = `${date}  ${time}`;
491	}
492	
493	// ---------------------------------------------------------------------------
494	// Auto-refresh
495	// ---------------------------------------------------------------------------
496	
497	function startAutoRefresh() {
498	  stopAutoRefresh();
499	  state.refreshTimer = setInterval(() => {
500	    fetchNews();
501	  }, state.refreshInterval);
502	}
503	
504	function stopAutoRefresh() {
505	  if (state.refreshTimer) {
506	    clearInterval(state.refreshTimer);
507	    state.refreshTimer = null;
508	  }
509	}
510	
511	// ---------------------------------------------------------------------------
512	// Event Handlers
513	// ---------------------------------------------------------------------------
514	
515	function bindEvents() {
516	  // Sentiment filter buttons
517	  $$(".sentiment-filter-btn").forEach((btn) => {
518	    btn.addEventListener("click", () => {
519	      const value = btn.dataset.sentiment;
520	      state.filter.sentiment = value;
521	      $$(".sentiment-filter-btn").forEach((b) => b.classList.remove("active"));
522	      btn.classList.add("active");
523	      renderNews();
524	    });
525	  });
526	
527	  // Search input
528	  const searchInput = $("#search-input");
529	  if (searchInput) {
530	    let debounceTimer;
531	    searchInput.addEventListener("input", (e) => {
532	      clearTimeout(debounceTimer);
533	      debounceTimer = setTimeout(() => {
534	        state.filter.query = e.target.value.trim();
535	        renderNews();
536	      }, 150);
537	    });
538	  }
539	
540	  // Date range inputs
541	  const dateFrom = $("#date-from");
542	  const dateTo = $("#date-to");
543	  if (dateFrom) {
544	    dateFrom.addEventListener("change", (e) => {
545	      state.filter.dateFrom = e.target.value;
546	      fetchNews();
547	    });
548	  }
549	  if (dateTo) {
550	    dateTo.addEventListener("change", (e) => {
551	      state.filter.dateTo = e.target.value;
552	      fetchNews();
553	    });
554	  }
555	  const clearDateBtn = $("#btn-clear-dates");
556	  if (clearDateBtn) {
557	    clearDateBtn.addEventListener("click", () => {
558	      state.filter.dateFrom = "";
559	      state.filter.dateTo = "";
560	      if (dateFrom) dateFrom.value = "";
561	      if (dateTo) dateTo.value = "";
562	      fetchNews();
563	    });
564	  }
565	
566	  // Hide duplicates toggle
567	  const hideDupsCb = $("#hide-duplicates");
568	  if (hideDupsCb) {
569	    hideDupsCb.addEventListener("change", (e) => {
570	      state.filter.hideDuplicates = e.target.checked;
571	      renderNews();
572	    });
573	  }
574	
575	  // Refresh button
576	  const refreshBtn = $("#btn-refresh");
577	  if (refreshBtn) {
578	    refreshBtn.addEventListener("click", forceRefresh);
579	  }
580	
581	  // Refresh interval selector
582	  const intervalSelect = $("#refresh-interval");
583	  if (intervalSelect) {
584	    intervalSelect.addEventListener("change", (e) => {
585	      state.refreshInterval = parseInt(e.target.value, 10);
586	      startAutoRefresh();
587	    });
588	  }
589	
590	  // API docs button
591	  const docsBtn = $("#btn-docs");
592	  if (docsBtn) {
593	    docsBtn.addEventListener("click", () => toggleModal(true));
594	  }
595	
596	  // Modal close
597	  const modalClose = $("#modal-close");
598	  if (modalClose) {
599	    modalClose.addEventListener("click", () => toggleModal(false));
600	  }
601	
602	  const modalOverlay = $("#modal-overlay");
603	  if (modalOverlay) {
604	    modalOverlay.addEventListener("click", (e) => {
605	      if (e.target === modalOverlay) toggleModal(false);
606	    });
607	  }
608	
609	  // Detail modal — row click (event delegation)
610	  const newsBody = $("#news-body");
611	  if (newsBody) {
612	    newsBody.addEventListener("click", (e) => {
613	      // Don't intercept link clicks — let them open in new tab
614	      if (e.target.closest("a")) return;
615	      const row = e.target.closest("tr[data-id]");
616	      if (!row) return;
617	      const itemId = row.dataset.id;
618	      const item = state.items.find((i) => String(i.id) === itemId);
619	      if (item) openDetailModal(item);
620	    });
621	  }
622	
623	  // Detail modal close
624	  const detailClose = $("#detail-modal-close");
625	  if (detailClose) {
626	    detailClose.addEventListener("click", closeDetailModal);
627	  }
628	  const detailOverlay = $("#detail-modal-overlay");
629	  if (detailOverlay) {
630	    detailOverlay.addEventListener("click", (e) => {
631	      if (e.target === detailOverlay) closeDetailModal();
632	    });
633	  }
634	
635	  // Sound toggle
636	  const soundBtn = $("#btn-sound");
637	  if (soundBtn) {
638	    soundBtn.addEventListener("click", () => {
639	      state.soundEnabled = !state.soundEnabled;
640	      soundBtn.classList.toggle("active", state.soundEnabled);
641	      soundBtn.title = state.soundEnabled ? "Sound alerts ON" : "Sound alerts OFF";
642	      const icon = soundBtn.querySelector(".sound-icon");
643	      if (icon) {
644	        icon.innerHTML = state.soundEnabled
645	          ? '<path d="M11 5L6 9H2v6h4l5 4V5z"/><path d="M19.07 4.93a10 10 0 010 14.14M15.54 8.46a5 5 0 010 7.07"/>'
646	          : '<path d="M11 5L6 9H2v6h4l5 4V5z"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/>';
647	      }
648	    });
649	  }
650	
651	  // Hamburger
652	  const hamburgerBtn = $("#hamburger-btn");
653	  if (hamburgerBtn) {
654	    hamburgerBtn.addEventListener("click", toggleSidebar);
655	  }
656	
657	  const sidebarBackdrop = $("#sidebar-backdrop");
658	  if (sidebarBackdrop) {
659	    sidebarBackdrop.addEventListener("click", () => toggleSidebar(false));
660	  }
